-- ============================================================
-- Seed: Daily Bible Verses (100 verses for recovery)
-- ============================================================

INSERT INTO daily_verses (reference, text, theme) VALUES

    ('መዝሙር 46:1', 'እግዚአብሔር መጠጊያችንና ኃይላችን፥ ባገኘን በታላቅ መከራም ረዳታችን ነው።', 'strength'),
    ('ሮሜ 8:28', 'እግዚአብሔርንም ለሚወዱት እንደ አሳቡም ለተጠሩት ነገር ሁሉ ለበጎ እንዲደረግ እናውቃለን።', 'hope'),
    ('ፊልጵ 4:13', 'ኃይልን በሚሰጠኝ በክርስቶስ ሁሉን እችላለሁ።', 'strength'),
    ('ኢሳ 41:10', 'እኔ ከአንተ ጋር ነኝና አትፍራ፤ እኔ አምላክህ ነኝና አትደንግጥ፤ አበረታሃለሁ፥ እረዳህማለሁ፥ በጽድቄም ቀኝ እደግፍሃለሁ።', 'comfort'),
    ('1 ቆሮንቶስ 10:13', 'ለሰው ሁሉ ከሚሆነው በቀር ምንም ፈተና አልደረሰባችሁም፤ ነገር ግን ከምትችሉት በላይ ትፈተኑ ዘንድ የማይፈቅድ እግዚአብሔር የታመነ ነው፥ ትታገሡም ዘንድ እንድትችሉ ከፈተናው ጋር መውጫውን ደግሞ ያደርግላችኋል።', 'temptation'),
    ('ያዕቆብ 4:7', 'እንግዲህ ለእግዚአብሔር ተገዙ፤ ዲያብሎስን ግን ተቃወሙት ከእናንተም ይሸሻል።', 'temptation'),
    ('ገላትያ 5:1', 'በነጻነት ልንኖር ክርስቶስ ነጻ አወጣን፤ እንግዲህ ጸንታችሁ ቁሙ፥ እንደ ገናም በባርነት ቀንበር አትያዙ።', 'freedom'),
    ('ዮሐንስ 8:36', 'እንግዲህ ልጁ አርነት ቢያወጣችሁ በእውነት አርነት ትወጣላችሁ።', 'freedom'),
    ('ሮሜ 6:14', 'ኃጢአት አይገዛችሁምና፤ ከጸጋ በታች እንጂ ከሕግ በታች አይደላችሁምና።', 'freedom'),
    ('2 ቆሮንቶስ 5:17', 'ስለዚህ ማንም በክርስቶስ ቢሆን አዲስ ፍጥረት ነው፤ አሮጌው ነገር አልፏል፤ እነሆ፥ ሁሉም አዲስ ሆኗል።', 'renewal'),
    ('ሰቆቃው ኤርምያስ 3:22-23', 'ያልጠፋነው ከእግዚአብሔር ምሕረት የተነሣ ነው፤ ርኅራኄው አያልቅምና። ማለዳ ማለዳ አዲስ ነው፤ ታማኝነትህ ታላቅ ነው።', 'renewal'),
    ('መዝሙር 51:10', 'አቤቱ፥ ንጹሕ ልብን ፍጠርልኝ፥ የቀናውንም መንፈስ በውስጤ አድስ።', 'renewal'),
    ('ሮሜ 12:2', 'የእግዚአብሔር ፈቃድ እርሱም በጎና ደስ የሚያሰኝ ፍጹምም የሆነው ነገር ምን እንደ ሆነ ፈትናችሁ ታውቁ ዘንድ በልባችሁ መታደስ ተለወጡ እንጂ ይህን ዓለም አትምሰሉ።', 'transformation'),
    ('ኤፌሶን 4:22-24', 'ፊተኛ ኑሮአችሁን እያሰባችሁ እንደሚያታልል ምኞት የሚጠፋውን አሮጌውን ሰው እስወግዱ፥ በአእምሮአችሁም መንፈስ ታደሱ፥ ለእውነትም በሚሆኑ  ጽድቅ እና ቅድስና  እንደ እግዚአብሔር ምሳሌ የተፈጠረውን አዲሱን ሰው ልበሱ።', 'transformation'),
    ('መዝሙር 34:18', 'እግዚአብሔር ልባቸው ለተሰበረ ቅርብ ነው፥ መንፈሳቸው የተሰበረውንም ያድናቸዋል።', 'comfort'),
    ('ማቴዎስ 11:28', 'እናንተ ደካሞች ሸክማችሁ የከበደ ሁሉ፥ ወደ እኔ ኑ፥ እኔም አሳርፋችኋለሁ።', 'comfort'),
    ('ኢሳይያስ 43:2', 'በውኃ ውስጥ ባለፍህ ጊዜ ከአንተ ጋር እሆናለሁ፥ በወንዞችም ውስጥ ባለፍህ ጊዜ አያሰጥሙህም፤ በእሳትም ውስጥ በሄድህ ጊዜ አትቃጠልም፥ ነበልባሉም አይፈጅህም', 'comfort'),
    ('መዝሙር 23:4', 'በሞት ጥላ መካከል እንኳ ብሄድ አንተ ከእኔ ጋር ነህና ክፉን አልፈራም፤ በትርህና ምርኩዝህ እነርሱ ያጽናኑኛል።', 'comfort'),
    ('ሮሜ 8:37', 'በዚህ ሁሉ ግን በወደደን በእርሱ ከአሸናፊዎች እንበልጣለን።', 'victory'),
    ('1 ዮሐንስ 4:4', 'ልጆች ሆይ፥ እናንተ ከእግዚአብሔር ናችሁ አሸንፋችኋቸውማል፥ በዓለም ካለው ይልቅ በእናንተ ያለው ታላቅ ነውና።', 'victory'),
    ('ራዕይ 12:11', 'እነርሱም ከበጉ ደም የተነሣ ከምስክራቸውም ቃል የተነሣ ድል ነሡት፥ ነፍሳቸውንም እስከ ሞት ድረስ አልወደዱም።', 'victory'),
    ('መዝሙር 18:2', 'እግዚአብሔር ዓለቴ፥ አምባዬ፥ መድኃኒቴ፥ አምላኬ፥ በእርሱም የምተማመንበት ረዳቴ፥ መታመኛዬና የደኅንነቴ ቀንድ መጠጊያዬም ነው።', 'strength'),
    ('ኢሳይያስ 40:31', 'እግዚአብሔርን በመታመን የሚጠባበቁ ግን ኃይላቸውን ያድሳሉ፤ እንደ ንስር በክንፍ ይወጣሉ፤ ይሮጣሉ፥ አይታክቱም፤ ይሄዳሉ፥ አይደክሙም።', 'strength'),
    ('ኤፌሶን 6:11', 'የዲያብሎስን ሽንገላ ትቃወሙ ዘንድ እንዲቻላችሁ የእግዚአብሔርን ዕቃ ጦር ሁሉ ልበሱ።', 'temptation'),
    ('1 ጴጥሮስ 5:8', 'በመጠን ኑሩ ንቁም፥ ባላጋራችሁ ዲያብሎስ የሚውጠውን ፈልጎ እንደሚያገሣ አንበሳ ይዞራልና፤', 'temptation'),
    ('ዕብራውያን 4:15', 'ከኃጢአት በቀር በነገር ሁሉ እንደ እኛ የተፈተነ ነው እንጂ፥ በድካማችን ሊራራልን የማይችል ሊቀ ካህናት የለንም።', 'temptation'),
    ('ዕብራውያን 12:1', 'እንግዲህ እነዚህን የሚያህሉ ምስክሮች እንደ ደመና በዙሪያችን ካሉልን፥ እኛ ደግሞ ሸክምን ሁሉ ቶሎም የሚከበንን ኃጢአት አስወግደን፥ የእምነታችንንም ራስና ፈጻሚውን ኢየሱስን ተመልክተን፥ በፊታችን ያለውን ሩጫ በትዕግሥት እንሩጥ፤', 'perseverance'),
    ('ያዕቆብ 1:12', 'በፈተና የሚጸና ሰው የተባረከ ነው፤ ከተፈተነ በኋላ ለሚወዱት ተስፋ ስለ እርሱ የሰጣቸውን የሕይወትን አክሊል ይቀበላልና።', 'perseverance'),
    ('ፊልጵ 3:14', 'በክርስቶስ ኢየሱስ ከፍ ከፍ ያለውን የእግዚአብሔርን መጥራት ዋጋ እንዳገኝ ምልክትን እፈጥናለሁ።', 'perseverance'),
    ('መዝሙር 40:1-2', 'ቆይቼ እግዚአብሔር ደጅ ጠናሁት፥ እርሱም ዘንበል አለልኝ ጩኽቴንም ሰማኝ። ከጥፋት ጕድጓድ ከረግረግም ጭቃ አወጣኝ፥ እግሮቼንም በድንጋይ ላይ አቆማቸው፥ አረማመዴንም አጸና።', 'hope'),
    ('ኤርምያስ 29:11', 'ለእናንተ የማስባትን አሳብ እኔ አውቃለሁ፤ ፍጻሜና ተስፋ እሰጣችሁ ዘንድ የሰላም አሳብ ነው እንጂ የክፉ ነገር አይደለም።', 'hope'),
    ('ሮሜ 15:13', 'የተስፋ አምላክም በመንፈስ ቅዱስ ኃይል በተስፋ እንድትበዙ በማመናችሁ ደስታንና ሰላምን ሁሉ ይሙላባችሁ።', 'hope'),
    ('መዝሙር 119:9', 'ጕልማሳ መንገዱን በምን ያነጻል? ቃልህን በመጠበቅ ነው።', 'purity'),
    ('ማቴዎስ 5:8', 'ልበ ንጹሖች ብፁዓን ናቸው፥ እግዚአብሔርን ያዩታልና።', 'purity'),
    ('1 ተሰሎንቄ 4:3', 'ይህ የእግዚአብሔር ፈቃድ እርሱም መቀደሳችሁ ነውና፤', 'purity'),
    ('ኢዮብ 31:1', 'ከዓይኔ ጋር ቃል ኪዳን ገባሁ፤እንግዲህስ ቈንጆይቱን እንዴት እመለከታለሁ?', 'purity'),
    ('መዝሙር 101:3', 'በዓይኖቼ ፊት ክፉ ነገርን አላኖርኩም፤ ሕግ ተላላፊዎችን ጠላሁ።', 'purity'),
    ('ምሳሌ 4:23', 'አጥብቀህ ልብህን ጠብቅ፥ የሕይወት መውጫ ከእርሱ ነውና።', 'wisdom'),
    ('ምሳሌ 3:5-6', 'በፍጹም ልብህ በእግዚአብሔር ታመን፥ በራስህም ማስተዋል አትደገፍ፤ በመንገድህ ሁሉ እርሱን እወቅ፥ እርሱም ጎዳናህን ያቀናልሃል።', 'wisdom'),
    ('ያዕቆብ 1:5', '	ከእናንተ ግን ማንም ጥበብ ቢጎድለው፥ ሳይነቅፍ በልግስና ለሁሉ የሚሰጠውን እግዚአብሔርን ይለምን፥ ለእርሱም ይሰጠዋል', 'wisdom'),
    ('1 ቆሮንቶስ 6:19-20', 'ወይስ ሥጋችሁ ከእግዚአብሔር የተቀበላችሁት በእናንተ የሚኖረው የመንፈስ ቅዱስ ቤተ መቅደስ እንደ ሆነ አታውቁምን? በዋጋ ተገዝታችኋልና ለራሳችሁ አይደላችሁም፤ ስለዚህ በሥጋችሁ እግዚአብሔርን አክብሩ።', 'purity'),
    ('ሮሜ 13:14', 'ነገር ግን ጌታን ኢየሱስ ክርስቶስን ልበሱት፥ ምኞቱንም እንዲፈጽም ለሥጋ አታስቡ።', 'temptation'),
    ('ቆላስይስ 3:2', 'በላይ ያለውን አስቡ እንጂ በምድር ያለውን አይደለም።', 'renewal'),
    ('2 ጢሞቴዎስ 2:22', 'ከክፉ የጎልማሳነት ምኞት ግን ሽሽ፥ በንጹሕም ልብ ጌታን ከሚጠሩ ጋር ጽድቅን እምነትን ፍቅርን ሰላምን አጥብቀህ ተከተል።', 'purity'),
    ('መዝሙር 86:5', 'አንተ፥ ጌታ ሆይ፥ ቸርና ይቅር ባይ ነህና፥ ለሚጠሩህም ሁሉ ምሕረትህ ብዙ ነውና።', 'forgiveness'),
    ('1 ዮሐንስ 1:9', 'በኃጢአታችን ብንናዘዝ ኃጢአታችንን ይቅር ሊለን ከአመጻም ሁሉ ሊያነጻን የታመነና ጻድቅ ነው።', 'forgiveness'),
    ('ሚክያስ 7:19', 'ተመልሶ ይምረናል፤ ክፋታችንንም ይጠቀጥቃል፥ ኃጢአታችንንም በባሕሩ ጥልቅ ይጥለዋል።', 'forgiveness'),
    ('መዝሙር 103:12', 'ምሥራቅ ከምዕራብ እንደሚርቅ፥ እንዲሁ ኃጢአታችንን ከእኛ አራቀ።', 'forgiveness'),
    ('ኢሳይያስ 1:18', 'ኑና እንዋቀስ ይላል እግዚአብሔር፤ ኃጢአታችሁ እንደ አለላ ብትሆን እንደ አመዳይ ትነጻለች፤ እንደ ደምም ብትቀላ እንደ ባዘቶ ትጠራለች።', 'forgiveness'),
    ('ሮሜ 8:1', 'እንግዲህ በክርስቶስ ኢየሱስ ላሉት አሁን ኵነኔ የለባቸውም።', 'forgiveness'),
    ('ኤፌሶን 1:7', 'በውድ ልጁም፥ እንደ ጸጋው ባለ ጠግነት መጠን፥ በደሙ የተደረገ ቤዛነታችንን አገኘን እርሱም የበደላችን ስርየት።', 'forgiveness'),
    ('ዕብራውያን 10:22', 'ከክፉ ሕሊና ለመንጻት ልባችንን ተረጭተን ሰውነታችንንም በጥሩ ውኃ ታጥበን በተረዳንበት እምነት በቅን ልብ እንቅረብ፤', 'forgiveness'),
    ('ገላትያ 6:1', 'ወንድሞች ሆይ፥ ሰው በማናቸውም በደል ቢገኝ፥ መንፈሳውያን የሆናችሁ እናንተ በየውሃት መንፈስ እንደዚህ ያለውን ሰው አቅኑት፤ አንተ ደግሞ እንዳትፈተን ራስህን ጠብቅ።', 'community'),
    ('ምሳሌ 27:17', 'ብረት ብረትን ይስለዋል፥ ሰውም ባልንጀራውን ይስላል።', 'community'),
    ('ዕብራውያን 10:24-25', 'ለፍቅርና ለመልካምም ሥራ እንድንነቃቃ እርስ በርሳችን እንተያይ፤ በአንዳንዶችም ዘንድ ልማድ እንደ ሆነው፥ መሰብሰባችንን አንተው እርስ በርሳችን እንመካከር እንጂ፤ ይልቁንም ቀኑ ሲቀርብ እያያችሁ አብልጣችሁ ይህን አድርጉ።', 'community'),
    ('መክብብ 4:9-10', 'ድካማቸው መልካም ዋጋ አለውና አንድ ብቻ ከመሆን ሁለት መሆን ይሻላል። ቢወድቁ አንዱ ሁለተኛውን ያነሣዋልና፤ አንዱ ብቻውን ሆኖ በወደቀ ጊዜ ግን የሚያነሣው ሁለተኛ የለውምና ወዮለት።', 'community'),
    ('ያዕቆብ 5:16', 'እርስ በርሳችን በኃጢአታችሁ ተናዘዙ። ትፈወሱም ዘንድ እያንዳንዱ ስለ ሌላው ይጸልይ፤ የጻድቅ ሰው ጸሎት በሥራዋ እጅግ ኃይል ታደርጋለች', 'community'),
    ('ማቴዎስ 18:20', 'ሁለት ወይም ሦስት በስሜ በሚሰበሰቡበት በዚያ በመካከላቸው እሆናለሁና።', 'community'),
    ('መዝሙር 55:22', 'ትካዜህን በእግዚአብሔር ላይ ጣል፥ እርሱም ይደግፍሃል፤ ለጻድቁም ለዘላለም ሁከትን አይሰጠውም።', 'trust'),
    ('ናሆም 1:7', 'እግዚአብሔር መልካም ነው፥ በመከራ ቀንም መሸሸጊያ ነው፤ በእርሱ የሚታመኑትንም ያውቃል።', 'trust'),
    ('መዝሙር 37:5', 'መንገድህን ለእግዚአብሔር አደራ ስጥ፥ በእርሱም ታመን፥ እርሱም ያደርግልሃል።', 'trust'),
    ('ኢሳይያስ 26:3', 'በአንተ ታምናለችና በአንተ ላይ ለተደገፈች ነፍስ ፈጽመህ በሰላም ትጠብቃታለህ።', 'peace'),
    ('ዮሐንስ 14:27', 'ሰላምን እተውላችኋለሁ፥ ሰላሜን እሰጣችኋለሁ፤ እኔ የምሰጣችሁ ዓለም እንደሚሰጥ አይደለም። ልባችሁ አይታወክ አይፍራም።', 'peace'),
    ('ፊልጵ 4:6-7', 'ጌታ ቅርብ ነው። በነገር ሁሉ በጸሎትና በምልጃ ከምስጋና ጋር በእግዚአብሔር ዘንድ ልመናችሁን አስታውቁ እንጂ በአንዳች አትጨነቁ። አእምሮንም ሁሉ የሚያልፍ የእግዚአብሔር ሰላም ልባችሁንና አሳባችሁን በክርስቶስ ኢየሱስ ይጠብቃል።', 'peace'),
    ('ሮሜ 5:1', 'እንግዲህ በእምነት ከጸደቅን በጌታችን በኢየሱስ ክርስቶስ በኩል በእግዚአብሔር ዘንድ ሰላምን እንያዝ፤', 'peace'),
    ('መዝሙር 32:1', 'መተላለፉ የቀረችለት ኃጢአቱም የተከደነችለት ምስጉን ነው።', 'blessing'),
    ('ዘኍልቍ 6:24-26', 'እግዚአብሔር ይባርክህ ይጠብቅህም፤ እግዚአብሔር ፊቱን ያብራልህ፥ ይራራልህም፤ እግዚአብሔር ፊቱን ወደ አንተ ያንሣ፥ ሰላምንም ይስጥህ።', 'blessing'),
    ('ዘዳግም 31:8', 'በፊትህም የሚሄድ እርሱ እግዚአብሔር ነው ከአንተ ጋር ይሆናል፥ አይጥልህም፥ አይተውህም አትፍራ፥ አትደንግጥ አለው።', 'courage'),
    ('ኢያሱ 1:9', 'በምትሄድበት ሁሉ አምላክህ እግዚአብሔር ከአንተ ጋር ነውና ጽና፥ አይዞህ፤ አትፍራ፥ አትደንግጥ ብዬ አላዘዝሁህምን?', 'courage'),
    ('2 ጢሞቴዎስ 1:7', 'እግዚአብሔር የኃይልና የፍቅር ራስንም የመግዛት መንፈስ እንጂ የፍርሃት መንፈስ አልሰጠንምና።', 'courage'),
    ('መዝሙር 27:1', 'እግዚአብሔር ብርሃኔና መድኃኒቴ ነው፤ የሚያስፈራኝ ማን ነው? እግዚአብሔር የሕይወቴ መታመኛዋ ነው፤ የሚያስደነግጠኝ ማን ነው?', 'courage'),
    ('ዕብራውያን 13:5', 'አካሄዳችሁ ገንዘብን ያለ መውደድ ይሁን፥ ያላችሁም ይብቃችሁ፤ እርሱ ራሱ፦ አልለቅህም ከቶም አልተውህም ብሎአልና፤', 'trust'),
    ('መዝሙር 145:18', 'እግዚአብሔር ለሚጠሩት ሁሉ፥ በእውነት ለሚጠሩት ሁሉ ቅርብ ነው።', 'trust'),
    ('ሮሜ 8:38-39', 'ሞት ቢሆን፥ ሕይወትም ቢሆን፥ መላእክትም ቢሆኑ፥ ግዛትም ቢሆን፥ ያለውም ቢሆን፥ የሚመጣውም ቢሆን፥ ኃይላትም ቢሆኑ፥ከፍታም ቢሆን፥ ዝቅታም ቢሆን፥ ልዩ ፍጥረትም ቢሆን በክርስቶስ ኢየሱስ በጌታችን ካለ ከእግዚአብሔር ፍቅር ሊለየን እንዳይችል ተረድቼአለሁ።', 'love'),
    ('ዮሐንስ 3:16', 'በእርሱ የሚያምን ሁሉ የዘላለም ሕይወት እንዲኖረው እንጂ እንዳይጠፋ እግዚአብሔር አንድያ ልጁን እስኪሰጥ ድረስ ዓለሙን እንዲሁ ወዶአልና።', 'love'),
    ('1 ዮሐንስ 4:18', 'ፍጹም ፍቅር ፍርሃትን አውጥቶ ይጥላል እንጂ በፍቅር ፍርሃት የለም፤ ፍርሃት ቅጣት አለውና፤ የሚፈራም ሰው ፍቅሩ ፍጹም አይደለም።', 'love'),
    ('ሶፎንያስ 3:17', 'አምላክሽ እግዚአብሔር በመካከልሽ ታዳጊ ኃያል ነው፤ በደስታ በአንቺ ደስ ይለዋል፥ በፍቅሩም ያርፋል፥ በእልልታም በአንቺ ደስ ይለዋል ይባላል።', 'love'),
    ('1 ጴጥሮስ 1:13', 'ስለዚህ የልቦናችሁን ወገብ ታጥቃችሁና በመጠን ኖራችሁ፥ ኢየሱስ ክርስቶስ ሲገለጥ የምታገኙትን ጸጋ ፈጽማችሁ ተስፋ አድርጉ።', 'hope'),
    ('ቆላስይስ 1:13', 'እርሱ ከጨለማ ሥልጣን አዳነን፥ ቤዛነቱንም እርሱንም የኃጢአትን ስርየት ወዳገኘንበት ወደ ፍቅሩ ልጅ መንግሥት አፈለሰን።', 'freedom'),
    ('መዝሙር 107:13-14', 'በተጨነቁ ጊዜ ወደ እግዚአብሔር ጮኹ፥ በመከራቸውም አዳናቸው። ከጨለማና ከሞት ጥላ አወጣቸው፥ እስራታቸውንም ሰበረ።', 'freedom'),
    ('ሉቃስ 4:18', 'የጌታ መንፈስ በእኔ ላይ ነው፥ ለድሆች ወንጌልን እሰብክ ዘንድ ቀብቶኛልና፤ ለታሰሩትም መፈታትን ለዕውሮችም ማየትን እሰብክ ዘንድ፥ የተጠቁትንም ነጻ አወጣ ዘንድ የተወደደችውንም የጌታን ዓመት እሰብክ ዘንድ ልኮኛል', 'freedom'),
    ('የሐዋርያት ሥራ 3:19', 'እንግዲህ ከጌታ ፊት የመጽናናት ዘመን እንድትመጣላችሁ አስቀድሞም ለእናንተ የመረጠውን ኢየሱስ ክርስቶስን እንዲልክላችሁ፥ ኃጢአታችሁ ይደመሰስ ዘንድ ንስሐ ግቡ ተመለሱም።', 'renewal'),
    ('ኢሳይያስ 61:3', 'እግዚአብሔር ለክብሩ የተከላቸው የጽድቅ ዛፎች እንዲባሉ ለጽዮን አልቃሾች አደርግላቸው ዘንድ፥ በአመድ ፋንታ አክሊልን፥ በልቅሶም ፋንታ የደስታን ዘይት፥ በኀዘንም መንፈስ ፋንታ የምስጋናን መጐናጸፊያ እሰጣቸው ዘንድ ልኮኛል።', 'renewal'),
    ('ሕዝቅኤል 36:26', 'አዲስም ልብ እሰጣችኋለሁ አዲስም መንፈስ በውስጣችሁ አኖራለሁ፤ የድንጋዩንም ልብ ከሥጋችሁ አወጣለሁ የሥጋንም ልብ እሰጣችኋለሁ።', 'transformation'),
    ('2 ቆሮንቶስ 4:16', 'ስለዚህም አንታክትም፥ ነገር ግን የውጭው ሰውነታችን ቢጠፋ እንኳ የውስጡ ሰውነታችን ዕለት ዕለት ይታደሳል።', 'perseverance'),
    ('ሮሜ 5:3-4', 'ይህም ብቻ አይደለም፥ ነገር ግን መከራ ትዕግሥትን እንዲያደርግ፥ ትዕግሥትም ፈተናን ፈተናም ተስፋን እንዲያደርግ እያወቅን፥ በመከራችን ደግሞ እንመካለን፤', 'perseverance'),
    ('መዝሙር 46:10', 'ዕረፉ፥ እኔም አምላክ እንደ ሆንሁ እወቁ፤ በአሕዛብ ዘንድ ከፍ ከፍ እላለሁ፥ በምድርም ላይ ከፍ ከፍ እላለሁ።', 'peace'),
    ('ምሳሌ 28:13', 'ኃጢአቱን የሚሰውር አይለማም፤ የሚናዘዝባትና የሚተዋት ግን ምሕረትን ያገኛል።', 'forgiveness'),
    ('ማቴዎስ 5:3', 'በመንፈስ ድሆች የሆኑ ብፁዓን ናቸው፥ መንግሥተ ሰማያት የእነርሱ ናትና።', 'blessing'),
    ('መዝሙር 34:8', 'እግዚአብሔር ቸር እንደ ሆነ ቅመሱ እዩም፤ በእርሱ የሚታመን ሰው ምስጉን ነው።', 'blessing'),
    ('ኤፌሶን 3:20', 'እንግዲህ በእኛ እንደሚሠራው ኃይል መጠን ከምንለምነው ወይም ከምናስበው ሁሉ ይልቅ እጅግ አብልጦ ሊያደርግ ለሚቻለው፥', 'hope'),
    ('ፊልጵ 1:6', 'በእናንተ መልካምን ሥራ የጀመረው እስከ ኢየሱስ ክርስቶስ ቀን ድረስ እንዲፈጽመው ይህን ተረድቼአለሁና፤', 'hope'),
    ('መዝሙር 71:20', 'ብዙ ጭንቀትንና መከራን አሳይተኸኛልና፥ ተመለስህ ሕያውም አደረግኸኝ፤ ከምድር ጥልቅም እንደ ገና አወጣኸኝ።', 'hope'),
    ('ኢዮኤል 2:25', 'የሰደድሁባችሁ ታላቁ ሠራዊቴ አንበጣና ደጎብያ ኩብኩባና ተምች የበላቸውን ዓመታት እመልስላችኋለሁ።', 'restoration'),
    ('ኢሳይያስ 43:19', 'እነሆ፥ አዲስ ነገርን አደርጋለሁ፤ እርሱም አሁን ይበቅላል፥ እናንተም አታውቁትምን? በምድረ በዳም መንገድን በበረሀም ወንዞችን አደርጋለሁ።', 'renewal'),
    ('መዝሙር 30:5', 'ቍጣው ለጥቂት ጊዜ ነው፥ ሞገሱ ግን ለሕይወት ዘመን፤ ልቅሶ ማታ ይመጣል፥ ጥዋት ግን ደስታ ይሆናል።', 'hope')
;